    <button id="backToTopBtn" onclick="scrollToTop()" class="fixed bottom-6 right-6 md:bottom-10 md:right-10 bg-blue-600 text-white w-12 h-12 md:w-14 md:h-14 rounded-full flex items-center justify-center shadow-lg hover:bg-blue-700 hover:shadow-2xl hover:-translate-y-2 transition-all duration-300 opacity-0 pointer-events-none z-50 focus:outline-none ring-4 ring-blue-100/50">
